Code Good:
@Model
class Product {
  var name: String
  var price: Double
  var category: String
  var isFavorite: Bool = false

  init(name: String, price: Double, category: String) {
    self.name = name
    self.price = price
    self.category = category
  }
}

struct ProductListView: View {
  @Query(sort: \Product.name) var products: [Product]
  @Environment(\.modelContext) var context

  var body: some View {
    List(products) { product in ProductRow(product: product) }
  }
}

struct ProductListView: View {
  @State private var products: [Product] = []

  var body: some View {
    List(products) { ProductRow(product: $0) }
      .task {
        do {
          products = try await productService.fetchAll()
        } catch {
          // handle error
        }
      }
      .refreshable {
        products = try await productService.fetchAll()
      }
  }
}

